// frontend/src/pages/rider/RiderDashboard.js
import React, { useEffect, useState } from "react";
import {
  Box, Card, CardContent, Typography, Button, Grid
} from "@mui/material";
import { MapContainer, TileLayer, Marker, Popup } from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import axios from "axios";
import { useAuth } from "../../contexts/AuthContext";
import { io } from "socket.io-client";

const socket = io("http://localhost:5000");

export default function RiderDashboard() {
  const [pendingRides, setPendingRides] = useState([]);
  const [currentLocation, setCurrentLocation] = useState(null);
  const { auth } = useAuth();

  // 📍 Register driver
  useEffect(() => {
    if (auth?.user?._id) {
      socket.emit("registerDriver", auth.user._id);
    }
  }, [auth]);

  // 📍 Get location
  useEffect(() => {
    const watchId = navigator.geolocation.watchPosition(
      (pos) => {
        const coords = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setCurrentLocation(coords);
        socket.emit("driverLocation", { driverId: auth.user._id, coords });
      },
      (err) => console.error("Location error:", err),
      { enableHighAccuracy: true }
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, [auth]);

  // Fetch pending rides
  const fetchPending = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/rides/pending", {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      setPendingRides(res.data.rides || []);
    } catch {
      console.error("Failed to fetch rides");
    }
  };

  useEffect(() => {
    fetchPending();
    socket.on("rideRequest", () => fetchPending());
    return () => {
      socket.off("rideRequest");
    };
  }, []);

  // Accept ride
  const acceptRide = async (id) => {
    try {
      await axios.post(`http://localhost:5000/api/rides/${id}/accept`, {}, {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      fetchPending();
    } catch {
      console.error("Accept failed");
    }
  };

  // Reject ride
  const rejectRide = async (id) => {
    try {
      await axios.post(`http://localhost:5000/api/rides/${id}/reject`, {}, {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      fetchPending();
    } catch {
      console.error("Reject failed");
    }
  };

  const driverIcon = new L.Icon({
    iconUrl: "https://cdn-icons-png.flaticon.com/512/64/64113.png",
    iconSize: [35, 35],
  });

  return (
    <Box p={4}>
      <Typography variant="h4" gutterBottom>Driver Dashboard</Typography>

      {/* Live Map */}
      <Card sx={{ mb: 3, p: 2 }}>
        <Typography variant="h6">Your Location</Typography>
        {currentLocation && (
          <MapContainer center={currentLocation} zoom={13} style={{ height: "400px", width: "100%" }}>
            <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
            <Marker position={currentLocation} icon={driverIcon}>
              <Popup>You are here</Popup>
            </Marker>
          </MapContainer>
        )}
      </Card>

      {/* Pending Rides */}
      <Typography variant="h5" gutterBottom>Ride Requests</Typography>
      <Grid container spacing={2}>
        {pendingRides.length === 0 ? (
          <Typography>No rides available</Typography>
        ) : (
          pendingRides.map((ride) => (
            <Grid item xs={12} md={6} key={ride._id}>
              <Card sx={{ borderRadius: 3, boxShadow: 2 }}>
                <CardContent>
                  <Typography>Pickup: {ride.pickup}</Typography>
                  <Typography>Drop: {ride.drop}</Typography>
                  <Typography>Status: {ride.status}</Typography>
                  <Box mt={2} display="flex" gap={2}>
                    <Button variant="contained" color="success" onClick={() => acceptRide(ride._id)}>
                      Accept
                    </Button>
                    <Button variant="contained" color="error" onClick={() => rejectRide(ride._id)}>
                      Reject
                    </Button>
                  </Box>
                </CardContent>
              </Card>
            </Grid>
          ))
        )}
      </Grid>
    </Box>
  );
}
